extern module ext_mod #(parameter int WIDTH = 8) (
  input  logic [WIDTH-1:0] in_data,
  output logic [WIDTH-1:0] out_data
);

logic [7:0]  a8,  b8;
logic [15:0] a16, b16;

ext_mod #(.WIDTH(8))  u0 (.in_data(a8),  .out_data(b8));
ext_mod #(.WIDTH(16)) u1 (.in_data(a16), .out_data(b16));
